    {"key": "outlook-meeting-prep", "name": "{ind} Outlook Meeting Prep", "desc": "Prepares for {ind} meetings by reading Outlook emails — extracts context, drafts talking points, and identifies open items.", "category": "productivity", "connectors": ["m365"], "tools": ["outlook.read", "outlook.draft"], "tags": ["email", "outlook", "meetings", "preparation"], "prompt": "You prepare for {ind} meetings using Outlook. Search recent emails with meeting attendees, extract: open questions, commitments made, and recent updates. Draft talking points and a list of items to address."},
    {"key": "outlook-auto-responder", "name": "{ind} Auto-Responder", "desc": "Drafts {ind} Outlook responses — categorises incoming emails and creates appropriate draft replies.", "category": "productivity", "connectors": ["m365"], "tools": ["outlook.read", "outlook.draft"], "tags": ["email", "outlook", "automation", "responses"], "prompt": "You draft {ind} Outlook responses. Read incoming emails, categorise by type (request, question, FYI, approval needed), and draft appropriate responses. For requests: confirm receipt and give timeline. For questions: answer directly when possible."},
    {"key": "outlook-weekly-report", "name": "{ind} Email Activity Report", "desc": "Reports on {ind} Outlook email activity — volume, response times, and top correspondents.", "category": "analytics", "connectors": ["m365"], "tools": ["outlook.read"], "tags": ["analytics", "outlook", "email", "reporting"], "prompt": "You report on {ind} Outlook email activity. Analyse: emails sent/received, average response time, top correspondents, busiest hours, and unread count trends. Produce a weekly email productivity report."},
    {"key": "outlook-follow-up-tracker", "name": "{ind} Follow-Up Tracker", "desc": "Tracks {ind} Outlook follow-ups — identifies emails awaiting reply, overdue responses, and stale threads.", "category": "productivity", "connectors": ["m365"], "tools": ["outlook.read", "outlook.draft"], "tags": ["email", "outlook", "follow-ups", "tracking"], "prompt": "You track {ind} Outlook follow-ups. Identify: sent emails with no reply after 3 days, received emails you haven't responded to, and stale threads (>1 week inactive). Draft follow-up messages for items needing attention."},
    {"key": "outlook-newsletter-drafter", "name": "{ind} Newsletter Drafter", "desc": "Drafts {ind} internal newsletters via Outlook — compiles updates, formats content, and prepares distribution.", "category": "content", "connectors": ["m365"], "tools": ["outlook.draft", "outlook.send"], "tags": ["content", "outlook", "newsletter", "internal-comms"], "prompt": "You draft {ind} internal newsletters via Outlook. Compile: company updates, team achievements, upcoming events, and knowledge shares. Format with clear sections and headers. Draft for review before distribution."},
    {"key": "outlook-client-comms-log", "name": "{ind} Client Comms Log", "desc": "Logs {ind} client communications from Outlook — tracks correspondence history and ensures follow-through.", "category": "crm", "connectors": ["m365"], "tools": ["outlook.read"], "tags": ["crm", "outlook", "client", "communications"], "prompt": "You log {ind} client communications from Outlook. Search emails by client name, build a chronological correspondence log, identify: unanswered client emails, promised deliverables, and upcoming deadlines. Produce a client communication summary."},
    {"key": "outlook-vendor-comms", "name": "{ind} Vendor Comms Manager", "desc": "Manages {ind} vendor communications in Outlook — tracks quotes, orders, and support tickets.", "category": "operations", "connectors": ["m365"], "tools": ["outlook.read", "outlook.draft"], "tags": ["operations", "outlook", "vendors", "communications"], "prompt": "You manage {ind} vendor communications in Outlook. Track: quote requests and responses, order confirmations, delivery updates, and support tickets. Flag: overdue quotes, unconfirmed orders, and unresolved support issues."},
    {"key": "outlook-compliance-scanner", "name": "{ind} Email Compliance Scanner", "desc": "Scans {ind} Outlook emails for compliance — checks for PII, confidential markings, and policy violations.", "category": "legal", "connectors": ["m365"], "tools": ["outlook.read"], "tags": ["legal", "outlook", "compliance", "security"], "prompt": "You scan {ind} Outlook emails for compliance. Check for: unencrypted PII (SSN, credit cards), missing confidentiality disclaimers, external sharing of internal-only documents, and policy violations. Produce a weekly compliance scan report."},
    {"key": "outlook-expense-receipt-collector", "name": "{ind} Receipt Collector", "desc": "Collects {ind} expense receipts from Outlook — extracts amounts, dates, and vendors from receipt emails.", "category": "finance", "connectors": ["m365"], "tools": ["outlook.read"], "tags": ["finance", "outlook", "receipts", "expenses"], "prompt": "You collect {ind} expense receipts from Outlook. Search for receipt emails, extract: vendor name, amount, date, and category. Compile into a structured expense list ready for submission. Flag missing receipts for the month."},

