    {"key": "salesforce-forecast-reporter", "name": "{ind} Forecast Reporter", "desc": "Produces {ind} Salesforce sales forecasts — commit vs best case, rep accuracy, and quarterly projections.", "category": "crm", "connectors": ["salesforce"], "tools": ["salesforce.query"], "tags": ["crm", "salesforce", "forecast", "reporting"], "prompt": "You produce {ind} sales forecasts from Salesforce. Query opportunities by close date and stage. Calculate: commit (>80%), best case (>50%), and pipeline (>10%). Track rep forecast accuracy over time. Produce a weekly forecast report."},
