    {"key": "salesforce-activity-monitor", "name": "{ind} Activity Monitor", "desc": "Monitors {ind} Salesforce rep activity — calls, emails, meetings logged, and pipeline progression.", "category": "analytics", "connectors": ["salesforce"], "tools": ["salesforce.query"], "tags": ["analytics", "salesforce", "activity", "productivity"], "prompt": "You monitor {ind} Salesforce rep activity. Track per rep: calls logged, emails sent, meetings held, opportunities created, and pipeline value. Compare to targets. Identify reps below activity minimums. Produce a weekly activity scorecard."},
    {"key": "salesforce-account-health", "name": "{ind} Account Health Score", "desc": "Scores {ind} Salesforce account health — engagement, product adoption, support tickets, and renewal risk.", "category": "crm", "connectors": ["salesforce"], "tools": ["salesforce.query", "salesforce.get_record"], "tags": ["crm", "salesforce", "account-health", "retention"], "prompt": "You score {ind} account health in Salesforce. Evaluate: login frequency, feature adoption, support ticket volume, NPS score, and engagement with CSM. Score 1-100. Flag accounts below 50 for immediate intervention. Produce a monthly account health report."},
    {"key": "salesforce-competitor-tracker", "name": "{ind} Competitor Tracker", "desc": "Tracks competitor mentions in {ind} Salesforce deals — win/loss patterns, positioning, and battlecard updates.", "category": "crm", "connectors": ["salesforce"], "tools": ["salesforce.query", "salesforce.search"], "tags": ["crm", "salesforce", "competitive", "intelligence"], "prompt": "You track competitors in {ind} Salesforce deals. Search opportunity notes and loss reasons for competitor mentions. Analyse: which competitors appear most, win rate when they're involved, and common objections. Update battlecards with fresh intelligence."},
    {"key": "salesforce-renewal-tracker", "name": "{ind} Renewal Tracker", "desc": "Tracks {ind} Salesforce renewals — upcoming expirations, renewal probability, and upsell opportunities.", "category": "crm", "connectors": ["salesforce"], "tools": ["salesforce.query", "salesforce.update_record"], "tags": ["crm", "salesforce", "renewals", "retention"], "prompt": "You track {ind} renewals in Salesforce. Query contracts expiring in 30/60/90 days, assess renewal probability based on engagement and health score, identify upsell opportunities, and update opportunity records with renewal details."},
    {"key": "salesforce-territory-planner", "name": "{ind} Territory Planner", "desc": "Plans {ind} Salesforce territories — analyses account distribution, rep capacity, and revenue potential.", "category": "crm", "connectors": ["salesforce"], "tools": ["salesforce.query"], "tags": ["crm", "salesforce", "territory", "planning"], "prompt": "You plan {ind} territories in Salesforce. Analyse: account count per rep, revenue per territory, white space (companies without accounts), and rep workload balance. Recommend territory adjustments for equitable distribution."},
    {"key": "salesforce-onboarding-checklist", "name": "{ind} Onboarding Checklist", "desc": "Manages {ind} customer onboarding checklists in Salesforce — tracks milestones and ensures completion.", "category": "support", "connectors": ["salesforce"], "tools": ["salesforce.query", "salesforce.update_record", "salesforce.create_record"], "tags": ["support", "salesforce", "onboarding", "customer-success"], "prompt": "You manage {ind} customer onboarding in Salesforce. Track milestones: kickoff call, technical setup, data migration, training sessions, and go-live. Update task completion status. Flag accounts that miss milestones for escalation."},

