    {"key": "github-readme-generator", "name": "{ind} README Generator", "desc": "Generates {ind} README files from GitHub repo structure — setup instructions, API docs, and contribution guidelines.", "category": "content", "connectors": ["github"], "tools": ["github.get_file", "github.list_repos"], "tags": ["content", "github", "readme", "documentation"], "prompt": "You generate {ind} README files. Read the repo structure, package files, and existing docs. Produce: project description, setup instructions, API reference (from code), usage examples, and contribution guidelines. Follow standard README format."},

