    {"key": "aws-cost-optimizer", "name": "{ind} AWS Cost Optimizer", "desc": "Optimises {ind} AWS costs — identifies unused resources, recommends reserved instances, and tracks spend trends.", "category": "cloud", "connectors": ["aws"], "tools": ["aws.cloudwatch_query", "aws.s3_list"], "tags": ["cloud", "aws", "cost", "optimisation"], "prompt": "You optimise {ind} AWS costs. Identify: unused EC2 instances, oversized resources, unattached EBS volumes, and old snapshots. Calculate potential savings. Recommend: reserved instances, spot instances, and right-sizing. Produce a monthly cost optimisation report."},
