    {"key": "aws-security-auditor", "name": "{ind} AWS Security Auditor", "desc": "Audits {ind} AWS security — checks public S3 buckets, open security groups, and IAM policy issues.", "category": "cloud", "connectors": ["aws"], "tools": ["aws.s3_list", "aws.cloudwatch_query"], "tags": ["cloud", "aws", "security", "audit"], "prompt": "You audit {ind} AWS security. Check for: public S3 buckets, overly permissive IAM policies, unused access keys, and unencrypted resources. Score overall security posture. Produce a security audit report with remediation priorities."},
    {"key": "aws-backup-verifier", "name": "{ind} Backup Verifier", "desc": "Verifies {ind} AWS backups — checks S3 backup completeness, age, and recovery readiness.", "category": "cloud", "connectors": ["aws"], "tools": ["aws.s3_list", "aws.s3_get"], "tags": ["cloud", "aws", "backup", "disaster-recovery"], "prompt": "You verify {ind} AWS backups. Check: latest backup timestamps, backup size consistency, and critical data coverage. Flag: missed backups, unusually small backups (possible failures), and backups older than retention policy. Produce a backup health report."},
    {"key": "aws-deployment-tracker", "name": "{ind} Deployment Tracker", "desc": "Tracks {ind} AWS deployments — Lambda updates, S3 deployments, and CloudWatch metric changes post-deploy.", "category": "cloud", "connectors": ["aws", "slack"], "tools": ["aws.cloudwatch_query", "aws.lambda_invoke", "slack.send_message"], "tags": ["cloud", "aws", "deployment", "tracking"], "prompt": "You track {ind} AWS deployments. Monitor post-deployment: error rate changes, latency shifts, and resource utilisation. Alert in Slack if metrics degrade within 30 minutes of deployment. Produce a deployment impact report."},
