    {"key": "aws-capacity-planner", "name": "{ind} Capacity Planner", "desc": "Plans {ind} AWS capacity — analyses usage trends, forecasts growth, and recommends scaling strategies.", "category": "cloud", "connectors": ["aws"], "tools": ["aws.cloudwatch_query"], "tags": ["cloud", "aws", "capacity", "planning"], "prompt": "You plan {ind} AWS capacity. Analyse: CPU/memory utilisation trends, request volume growth, and storage consumption rates. Forecast 3-month and 6-month needs. Recommend: auto-scaling policies, reserved capacity purchases, and architecture changes."},

