    {"key": "intercom-bot-optimizer", "name": "{ind} Bot Optimizer", "desc": "Optimises {ind} Intercom chatbot flows — analyses failure points, improves responses, and reduces escalations.", "category": "support", "connectors": ["intercom"], "tools": ["intercom.list_conversations"], "tags": ["support", "intercom", "chatbot", "optimisation"], "prompt": "You optimise {ind} Intercom chatbot flows. Analyse: where users drop off, questions the bot can't answer, and unnecessary escalations to humans. Suggest: new bot responses, improved routing, and self-service content additions."},
    {"key": "intercom-weekly-metrics", "name": "{ind} Support Metrics", "desc": "Produces weekly {ind} Intercom metrics — conversation volume, response times, resolution rates, and team performance.", "category": "analytics", "connectors": ["intercom"], "tools": ["intercom.list_conversations"], "tags": ["analytics", "intercom", "metrics", "weekly"], "prompt": "You produce weekly {ind} Intercom metrics. Track: total conversations, first response time, resolution time, conversations per agent, CSAT average, and escalation rate. Compare to targets and last week. Produce a metrics dashboard."},
