    {"key": "calendly-no-show-tracker", "name": "{ind} No-Show Tracker", "desc": "Tracks {ind} Calendly no-shows — identifies repeat offenders and optimises reminder strategies.", "category": "analytics", "connectors": ["calendly"], "tools": ["calendly.list_events"], "tags": ["analytics", "calendly", "no-shows", "scheduling"], "prompt": "You track {ind} Calendly no-shows. Identify: no-show rate by event type, repeat no-show contacts, and time slots with highest no-show rates. Recommend: reminder improvements, overbooking strategies, and no-show penalties."},
