    {"key": "calendly-team-calendar", "name": "{ind} Team Calendar Manager", "desc": "Manages {ind} team Calendly schedules — balances bookings across team members and ensures coverage.", "category": "scheduling", "connectors": ["calendly"], "tools": ["calendly.list_events", "calendly.get_event_types"], "tags": ["scheduling", "calendly", "team", "load-balancing"], "prompt": "You manage {ind} team Calendly schedules. Monitor: bookings per team member, coverage gaps, and overbooking risk. Ensure fair distribution of meetings across the team and maintain adequate response time slots."},
