    {"key": "calendly-sales-pipeline-scheduler", "name": "{ind} Sales Scheduler", "desc": "Schedules {ind} sales meetings via Calendly — sends booking links at the right pipeline stage with personalised context.", "category": "crm", "connectors": ["calendly", "hubspot"], "tools": ["calendly.get_event_types", "hubspot.get_deals"], "tags": ["crm", "calendly", "sales", "scheduling"], "prompt": "You schedule {ind} sales meetings via Calendly. At each pipeline stage, send the right meeting type: discovery call for new leads, demo for qualified leads, proposal review for negotiation. Include personalised context from CRM data."},
