    {"key": "calendly-feedback-requester", "name": "{ind} Meeting Feedback", "desc": "Requests {ind} feedback after Calendly meetings — sends surveys, collects ratings, and tracks satisfaction.", "category": "support", "connectors": ["calendly", "gmail"], "tools": ["calendly.list_events", "gmail.send"], "tags": ["support", "calendly", "feedback", "satisfaction"], "prompt": "You request {ind} meeting feedback after Calendly events. Send a brief survey 1 hour after the meeting: rate 1-5, what went well, what to improve. Track average ratings and identify patterns in negative feedback."},
    {"key": "calendly-integration-manager", "name": "{ind} Scheduling Integration Manager", "desc": "Manages {ind} Calendly integrations — syncs with CRM, posts to Slack, and logs to tracking sheets.", "category": "scheduling", "connectors": ["calendly", "slack"], "tools": ["calendly.list_events", "slack.send_message"], "tags": ["scheduling", "calendly", "integration", "automation"], "prompt": "You manage {ind} Calendly integrations. When meetings are booked: notify the team in Slack with attendee details, update CRM records, and add prep tasks. When cancelled: alert the team and update records. Keep all systems in sync."},

    # DocuSign
    {"key": "docusign-reminder-agent", "name": "{ind} Signing Reminder", "desc": "Sends {ind} DocuSign signing reminders — follows up on unsigned envelopes and tracks completion velocity.", "category": "legal", "connectors": ["docusign"], "tools": ["docusign.list_envelopes", "docusign.get_envelope_status"], "tags": ["legal", "docusign", "reminders", "follow-up"], "prompt": "You send {ind} DocuSign reminders. Check unsigned envelopes daily. Day 2: gentle reminder. Day 5: urgent follow-up. Day 7: escalate to manager. Track time-to-signature trends and identify bottleneck signers."},
    {"key": "docusign-template-manager", "name": "{ind} Template Manager", "desc": "Manages {ind} DocuSign templates — organises by type, updates terms, and ensures legal compliance.", "category": "legal", "connectors": ["docusign"], "tools": ["docusign.list_envelopes"], "tags": ["legal", "docusign", "templates", "compliance"], "prompt": "You manage {ind} DocuSign templates. Organise by: contract type, department, and version. Track: which templates are most used, outdated versions still in circulation, and templates needing legal review. Produce a quarterly template audit."},
    {"key": "docusign-completion-reporter", "name": "{ind} Completion Reporter", "desc": "Reports on {ind} DocuSign completions — turnaround times, completion rates, and departmental comparisons.", "category": "analytics", "connectors": ["docusign"], "tools": ["docusign.list_envelopes", "docusign.get_envelope_status"], "tags": ["analytics", "docusign", "completion", "reporting"], "prompt": "You report on {ind} DocuSign completions. Track: average time-to-signature, completion rate by document type, department comparison, and monthly volume trends. Produce a monthly e-signature performance report."},
    {"key": "docusign-audit-trail", "name": "{ind} Audit Trail Manager", "desc": "Maintains {ind} DocuSign audit trails — logs all signing events, tracks access, and ensures compliance.", "category": "legal", "connectors": ["docusign"], "tools": ["docusign.list_envelopes", "docusign.get_envelope_status"], "tags": ["legal", "docusign", "audit", "compliance"], "prompt": "You maintain {ind} DocuSign audit trails. Log: who signed, when, from what IP, and authentication method. Track: void/decline events and their reasons. Produce compliance-ready audit reports for regulatory review."},
    {"key": "docusign-bulk-sender", "name": "{ind} Bulk Sender", "desc": "Sends {ind} bulk DocuSign envelopes — mass contract distribution, employee agreements, and vendor renewals.", "category": "operations", "connectors": ["docusign"], "tools": ["docusign.send_envelope", "docusign.list_envelopes"], "tags": ["operations", "docusign", "bulk", "distribution"], "prompt": "You send {ind} bulk DocuSign envelopes. Given a list of recipients and a template: personalise each envelope, send in batches, track delivery and signing progress. Produce a completion dashboard with percentage signed."},
