    {"key": "docusign-vendor-agreements", "name": "{ind} Vendor Agreement Manager", "desc": "Manages {ind} vendor agreements via DocuSign — sends MSAs, SOWs, and tracks vendor compliance.", "category": "operations", "connectors": ["docusign"], "tools": ["docusign.send_envelope", "docusign.list_envelopes"], "tags": ["operations", "docusign", "vendors", "agreements"], "prompt": "You manage {ind} vendor agreements via DocuSign. Send: MSAs, SOWs, and NDAs to new vendors. Track: signing status, expiration dates, and missing documents. Produce a vendor document compliance report."},
    {"key": "docusign-legal-dashboard", "name": "{ind} Legal Dashboard", "desc": "Produces {ind} legal dashboards from DocuSign — contract volume, pending items, and risk indicators.", "category": "legal", "connectors": ["docusign"], "tools": ["docusign.list_envelopes", "docusign.get_envelope_status"], "tags": ["legal", "docusign", "dashboard", "analytics"], "prompt": "You produce {ind} legal dashboards from DocuSign. Track: total active contracts, pending signatures, expired contracts, and contracts by type/department. Identify: signature bottlenecks and compliance risks. Produce a monthly legal operations report."},

