    {"key": "box-legal-hold-manager", "name": "{ind} Legal Hold Manager", "desc": "Manages {ind} legal holds in Box — places holds on relevant content, tracks scope, and prevents deletion.", "category": "legal", "connectors": ["box"], "tools": ["box.search", "box.list_folder"], "tags": ["legal", "box", "legal-hold", "ediscovery"], "prompt": "You manage {ind} legal holds in Box. Given a hold request: search for relevant documents by keywords, dates, and custodians. Place holds to prevent deletion. Track hold scope and produce a custodian notification list."},
    {"key": "box-storage-optimizer", "name": "{ind} Storage Optimizer", "desc": "Optimises {ind} Box storage — identifies duplicates, large files, and recommends archival strategies.", "category": "storage", "connectors": ["box"], "tools": ["box.search", "box.list_folder"], "tags": ["storage", "box", "optimisation", "cost"], "prompt": "You optimise {ind} Box storage. Find: duplicate files, oversized folders, and stale content. Recommend: archival to cold storage, deletion of expired items, and deduplication. Estimate monthly cost savings from cleanup."},
    {"key": "box-audit-reporter", "name": "{ind} Box Audit Reporter", "desc": "Produces {ind} Box audit reports — file access logs, permission changes, and compliance metrics.", "category": "analytics", "connectors": ["box"], "tools": ["box.list_folder", "box.search"], "tags": ["analytics", "box", "audit", "compliance"], "prompt": "You produce {ind} Box audit reports. Track: file access frequency, permission changes, external sharing events, and download activity. Identify anomalies (unusual access patterns, bulk downloads). Produce quarterly audit summaries."},
