    {"key": "box-weekly-activity", "name": "{ind} Box Activity Report", "desc": "Produces {ind} weekly Box activity reports — uploads, downloads, shares, and collaboration trends.", "category": "analytics", "connectors": ["box"], "tools": ["box.list_folder"], "tags": ["analytics", "box", "activity", "weekly"], "prompt": "You produce weekly {ind} Box activity reports. Track: files uploaded/downloaded, new shared folders, collaboration events, and storage growth. Identify: most active folders and users. Produce a team collaboration health report."},

    # Figma
    {"key": "figma-component-auditor", "name": "{ind} Component Auditor", "desc": "Audits {ind} Figma components — checks library usage, detached instances, and design system compliance.", "category": "design", "connectors": ["figma"], "tools": ["figma.get_file", "figma.get_components"], "tags": ["design", "figma", "components", "audit"], "prompt": "You audit {ind} Figma components. Find: detached instances (should use library component), outdated components (old version), and custom elements that should be componentised. Produce a design system compliance score."},
