    {"key": "webflow-seo-optimizer", "name": "{ind} SEO Optimizer", "desc": "Optimises {ind} Webflow site SEO — meta tags, alt text, headings, and structured data.", "category": "marketing", "connectors": ["webflow"], "tools": ["webflow.list_items", "webflow.create_item"], "tags": ["marketing", "webflow", "seo", "optimisation"], "prompt": "You optimise {ind} Webflow SEO. Check CMS items for: missing meta titles/descriptions, alt text on images, proper heading hierarchy, and structured data. Fix issues and track organic traffic improvements."},
